}

public class NoLocationException extends IOException {

  private static final long serialVersionUID = 1L;

  public NoLocationException(String path, Class<?> t) {
    super("Cannot find locations for " + path + " in " + t.getSimpleName());
  }
}

public class AsyncCommitEvent extends CommitEvent {

    public AsyncCommitEvent(final Optional<Map<TopicPartition, OffsetAndMetadata>> offsets) {
        super(Type.COMMIT_ASYNC, offsets, Long.MAX_VALUE);
    }
}

public class CommitOnCloseEvent extends ApplicationEvent {

    public CommitOnCloseEvent() {
        super(Type.COMMIT_ON_CLOSE);
    }
}

public record CallbackRequest(Consumer<RequestLocal> fun, Request originalRequest) implements BaseRequest {

    @Override
    public String toString() {
        return "CallbackRequest(" + fun + ", " + originalRequest + ")";
    }
}

public enum WakeupRequest implements BaseRequest {
    INSTANCE;

    @Override
    public String toString() {
        return "WakeupRequest";
    }
}

public record LogDeleteRecordsResult(long requestedOffset, long lowWatermark, Optional<Throwable> exception) {
    public Errors error() {
        return exception
                .map(Errors::forException)
                .orElse(Errors.NONE);
    }
}

public record AlterPartitionItem(TopicIdPartition topicIdPartition, LeaderAndIsr leaderAndIsr,
                                 CompletableFuture<LeaderAndIsr> future) {
}

public record ClientSensors(Map<String, String> metricTags, Sensor quotaSensor, Sensor throttleTimeSensor) {
    public ClientSensors {
        metricTags = new LinkedHashMap<>(metricTags);
        Objects.requireNonNull(quotaSensor);
        Objects.requireNonNull(throttleTimeSensor);
    }
}

