@JsonTypeInfo(use = JsonTypeInfo.Id.NAME, property = "type")
public interface FilterFactory<E extends DeferredProcessingAware> extends Discoverable {

    Filter<E> build();
}

@JsonTypeInfo(use = JsonTypeInfo.Id.NAME, property = "type", defaultImpl = LogbackAccessRequestLogFactory.class)
public interface RequestLogFactory<T extends RequestLog> extends Discoverable {

    boolean isEnabled();

    T build(String name);
}

@GwtCompatible
@NullMarked
public interface TestBiMapGenerator<K extends @Nullable Object, V extends @Nullable Object>
    extends TestContainerGenerator<BiMap<K, V>, Entry<K, V>> {
  K[] createKeyArray(int length);

  V[] createValueArray(int length);
}

@GwtCompatible
@NullMarked
public interface TestListMultimapGenerator<K extends @Nullable Object, V extends @Nullable Object>
    extends TestMultimapGenerator<K, V, ListMultimap<K, V>> {}

@GwtCompatible
public interface TestSetMultimapGenerator<K, V>
    extends TestMultimapGenerator<K, V, SetMultimap<K, V>> {}

@GwtCompatible
@NullMarked
public interface TestMapGenerator<K extends @Nullable Object, V extends @Nullable Object>
    extends TestContainerGenerator<Map<K, V>, Map.Entry<K, V>> {
  K[] createKeyArray(int length);

  V[] createValueArray(int length);
}

@GwtCompatible
interface FilteredMultimap<K extends @Nullable Object, V extends @Nullable Object>
    extends Multimap<K, V> {
  Multimap<K, V> unfiltered();

  Predicate<? super Entry<K, V>> entryPredicate();
}

@GwtCompatible
interface FilteredSetMultimap<K extends @Nullable Object, V extends @Nullable Object>
    extends FilteredMultimap<K, V>, SetMultimap<K, V> {
  @Override
  SetMultimap<K, V> unfiltered();
}

@GwtIncompatible
interface SortedMultisetBridge<E extends @Nullable Object> extends Multiset<E> {
  @Override
  SortedSet<E> elementSet();
}

interface ClassCreatingMockMaker extends MockMaker {
    <T> Class<? extends T> createMockType(MockCreationSettings<T> settings);
}

public class InvocationComparator implements Comparator<Invocation> {
    @Override
    public int compare(Invocation o1, Invocation o2) {
        return Integer.compare(o1.getSequenceNumber(), o2.getSequenceNumber());
    }
}

public interface Http2SettingsAckFrame extends Http2Frame {
    Http2SettingsAckFrame INSTANCE = new DefaultHttp2SettingsAckFrame();

    @Override
    String name();
}

@FunctionalInterface
interface Http3FrameTypeValidator {

    Http3FrameTypeValidator NO_VALIDATION = (type, first) -> { };

    void validate(long type, boolean first) throws Http3Exception;
}

@FunctionalInterface
public interface IntervalBiFunction<T> extends BiFunction<Integer, Either<Throwable, T>, Long> {

    static <T> IntervalBiFunction<T> ofIntervalFunction(IntervalFunction f) {
        return (attempt, either) -> f.apply(attempt);
    }
}
